      totalSkus: 0,
      inStock: 0,
      lowStock: 0,
      backorder: 0,
      inventoryUnits: 0,
      catalogValue: 0,
    },
  );

  return {
    products,
    summary,
    lastSyncedAt: '2026-07-07T09:12:00.000Z',
  };
}

async function getCatalogData(): Promise<CatalogData> {
  'use cache';

  cacheTag(PRODUCTS_TAG);
